   474→func (db *DBReadOnly) loadDataAsQueryable(maxt int64) (storage.SampleAndChunkQueryable, error) {
   475→	select {
   476→	case <-db.closed:
   477→		return nil, ErrClosed
   478→	default:
   479→	}
   480→	blockReaders, err := db.Blocks()
   481→	if err != nil {
   482→		return nil, err
   483→	}
   484→	blocks := make([]*Block, len(blockReaders))
   485→	for i, b := range blockReaders {
   486→		b, ok := b.(*Block)
   487→		if !ok {
   488→			return nil, errors.New("unable to convert a read only block to a normal block")
   489→		}
   490→		blocks[i] = b
   491→	}
   492→
   493→	opts := DefaultHeadOptions()
   494→	opts.ChunkDirRoot = db.dir
   495→	head, err := NewHead(nil, db.logger, nil, nil, opts, NewHeadStats())
   496→	if err != nil {
   497→		return nil, err
   498→	}
   499→	maxBlockTime := int64(math.MinInt64)
   500→	if len(blocks) > 0 {
   501→		maxBlockTime = blocks[len(blocks)-1].Meta().MaxTime
   502→	}
   503→
   504→	// Also add the WAL if the current blocks don't cover the requests time range.
   505→	if maxBlockTime <= maxt {
   506→		if err := head.Close(); err != nil {
   507→			return nil, err
   508→		}
   509→		w, err := wlog.Open(db.logger, filepath.Join(db.dir, "wal"))
   510→		if err != nil {
   511→			return nil, err
   512→		}
   513→		var wbl *wlog.WL
   514→		wblDir := filepath.Join(db.dir, wlog.WblDirName)
   515→		if _, err := os.Stat(wblDir); !os.IsNotExist(err) {
   516→			wbl, err = wlog.Open(db.logger, wblDir)
   517→			if err != nil {
   518→				return nil, err
   519→			}
   520→		}
   521→		opts := DefaultHeadOptions()
   522→		opts.ChunkDirRoot = db.dir
   523→		head, err = NewHead(nil, db.logger, w, wbl, opts, NewHeadStats())
   524→		if err != nil {
   525→			return nil, err
   526→		}
   527→		// Set the min valid time for the ingested wal samples
   528→		// to be no lower than the maxt of the last block.
   529→		if err := head.Init(maxBlockTime); err != nil {
   530→			return nil, fmt.Errorf("read WAL: %w", err)
   531→		}
   532→		// Set the wal and the wbl to nil to disable related operations.
   533→		// This is mainly to avoid blocking when closing the head.
   534→		head.wal = nil
   535→		head.wbl = nil
   536→	}
   537→
   538→	db.closers = append(db.closers, head)
   539→	return &DB{
   540→		dir:    db.dir,
   541→		logger: db.logger,
   542→		blocks: blocks,
   543→		head:   head,
   544→	}, nil
   545→}
