   547→// Querier loads the blocks and wal and returns a new querier over the data partition for the given time range.
   548→// Current implementation doesn't support multiple Queriers.
   549→func (db *DBReadOnly) Querier(mint, maxt int64) (storage.Querier, error) {
   550→	q, err := db.loadDataAsQueryable(maxt)
