   567→// Blocks returns a slice of block readers for persisted blocks.
   568→func (db *DBReadOnly) Blocks() ([]BlockReader, error) {
   569→	select {
   570→	case <-db.closed:
   571→		return nil, ErrClosed
   572→	default:
   573→	}
   574→	loadable, corrupted, err := openBlocks(db.logger, db.dir, nil, nil)
   575→	if err != nil {
   576→		return nil, err
   577→	}
   578→
   579→	// Corrupted blocks that have been superseded by a loadable block can be safely ignored.
   580→	for _, block := range loadable {
   581→		for _, b := range block.Meta().Compaction.Parents {
   582→			delete(corrupted, b.ULID)
   583→		}
   584→	}
   585→	if len(corrupted) > 0 {
   586→		for _, b := range loadable {
   587→			if err := b.Close(); err != nil {
   588→				level.Warn(db.logger).Log("msg", "Closing block failed", "err", err, "block", b)
   589→			}
   590→		}
   591→		errs := tsdb_errors.NewMulti()
   592→		for ulid, err := range corrupted {
   593→			if err != nil {
   594→				errs.Add(fmt.Errorf("corrupted block %s: %w", ulid.String(), err))
   595→			}
   596→		}
   597→		return nil, errs.Err()
   598→	}
