  1355→// compactBlocks compacts all the eligible on-disk blocks.
  1356→// The compaction mutex should be held before calling this method.
  1357→func (db *DB) compactBlocks() (err error) {
  1358→	// Check for compactions of multiple blocks.
  1359→	for {
